// ── 2. Context Compression (/compact command) ─────────────────────────────────
// Summarizes a conversation thread to free context window space.
// Inspired by Claude Code's /compact command which summarizes the conversation
// to allow longer sessions without hitting context limits.
export async function compactThread(
  thread: Array<{ query: string; answer: string }>
): Promise<{ summary: string; turnCount: number; originalChars: number; compressedChars: number }> {
  const apiKey = getApiKey();
  if (!apiKey) throw new Error("DEEPSEEK_API_KEY or LLM_API_KEY not configured");

  const threadText = thread
    .map((t, i) => `Turn ${i + 1}:\nUser: ${t.query}\nAssistant: ${t.answer.slice(0, 2000)}`)
    .join("\n\n---\n\n");

  const originalChars = threadText.length;

  const response = await fetch(getApiUrl(), {
    method: "POST",
    headers: { Authorization: `Bearer ${apiKey}`, "Content-Type": "application/json", ...getProviderHeaders() },
    body: JSON.stringify({
      model: getActiveModel(),
      messages: [
        {
          role: "system",
          content: `You are a conversation summarizer. Compress the following conversation thread into a dense, information-rich summary that preserves all key facts, decisions, code snippets, and conclusions. The summary will be used as context for future turns in the same conversation.

Format: Write a single flowing summary paragraph followed by a ## Key Points section with bullet points for the most important facts, decisions, or code. Maximum 600 words total.`,
        },
        {
          role: "user",
          content: `Compress this conversation:\n\n${threadText}`,
        },
      ],
      max_tokens: 1000,
      temperature: 0.3,
    }),
  });

  if (!response.ok) throw new Error(`Compact failed: ${response.status}`);
  const data = (await response.json()) as any;
  const summary = data.choices?.[0]?.message?.content || "Conversation summary unavailable.";

  return {
    summary,
    turnCount: thread.length,
    originalChars,
    compressedChars: summary.length,
  };
}

// ── 3. TodoTool (structured task tracking) ───────────────────────────────────
// In-memory todo list for the current session. Inspired by Claude Code's
// TodoWriteTool / TodoReadTool which give the agent a persistent task list
// it can update as it works through complex multi-step tasks.
interface TodoItem {
  id: string;
  content: string;
  status: "pending" | "executing" | "done" | "cancelled";
  priority: "high" | "medium" | "low";
  createdAt: string;
  updatedAt: string;
}

const todoStore: Map<string, TodoItem> = new Map();

// v5.34: Periodic cleanup — evict completed/cancelled todos older than 1 hour,
// and all todos older than 24 hours to prevent unbounded memory growth
setInterval(() => {
  const now = Date.now();
  const ONE_HOUR = 3600_000;
  const ONE_DAY = 86400_000;
  for (const [id, item] of Array.from(todoStore.entries())) {
    const age = now - new Date(item.updatedAt).getTime();
    if ((item.status === "done" || item.status === "cancelled") && age > ONE_HOUR) {
      todoStore.delete(id);
    } else if (age > ONE_DAY) {
      todoStore.delete(id);
    }
  }
}, 300_000).unref(); // Check every 5 minutes

export function todoCreate(content: string, priority: "high" | "medium" | "low" = "medium"): TodoItem {
  const id = `todo_${Date.now()}_${Math.random().toString(36).slice(2, 7)}`;
  const now = new Date().toISOString();
  const item: TodoItem = { id, content, status: "pending", priority, createdAt: now, updatedAt: now };
  todoStore.set(id, item);
  return item;
}

export function todoUpdate(id: string, updates: Partial<Pick<TodoItem, "status" | "content" | "priority">>): TodoItem | null {
  const item = todoStore.get(id);
  if (!item) return null;
  Object.assign(item, updates, { updatedAt: new Date().toISOString() });
  todoStore.set(id, item);
  return item;
}

export function todoList(): TodoItem[] {
  return Array.from(todoStore.values()).sort((a, b) => {
    const priorityOrder = { high: 0, medium: 1, low: 2 };
    if (priorityOrder[a.priority] !== priorityOrder[b.priority]) {
      return priorityOrder[a.priority] - priorityOrder[b.priority];
    }
    return new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime();
  });
}

export function todoDelete(id: string): boolean {
  return todoStore.delete(id);
}

export function todoClear(): void {
  todoStore.clear();
}

// ── 4. ANDROMEDA.md writer ─────────────────────────────────────────────────────
// Allows Andromeda to write/update its own ANDROMEDA.md memory file,
// similar to how Claude Code can update CLAUDE.md with project notes.
export async function writeAndromedaMemory(content: string): Promise<{ path: string; chars: number }> {
  const workspaceRoot = process.env.WORKSPACE_ROOT || path.join(process.cwd(), "workspace");
  const memPath = path.join(workspaceRoot, "ANDROMEDA.md");
  try {
    if (!fs.existsSync(workspaceRoot)) {
      fs.mkdirSync(workspaceRoot, { recursive: true });
    }
    fs.writeFileSync(memPath, content, "utf-8");
    return { path: memPath, chars: content.length };
  } catch (err) {
    throw new Error(`Failed to write ANDROMEDA.md: ${(err as Error).message}`);
  }
}

export function readAndromedaMemory(): string | null {
  try {
    const workspaceRoot = process.env.WORKSPACE_ROOT || path.join(process.cwd(), "workspace");
    const memPath = path.join(workspaceRoot, "ANDROMEDA.md");
    if (fs.existsSync(memPath)) {
      return fs.readFileSync(memPath, "utf-8");
    }
  } catch (err) { log.caught("ignore", err); }
  return null;
}

/**
 * codeIntel.ts — Code Intelligence Layer for Andromeda v4.8
 *
 * Provides developer-focused tools that ground the AI in real, verifiable data:
 *
 * 1. DEPENDENCY RESOLVER — Reads the actual package.json and fetches live
 *    version data from the npm registry. Never invents version numbers.
 *
 * 2. ERROR EXPLAINER — Takes a raw error/stack trace and produces a structured
 *    diagnosis with the exact file, line, and a targeted fix suggestion.
 *
 * 3. WORKSPACE CODE SEARCH — Performs a real grep across workspace files so
 *    the AI can find actual function names, imports, and patterns.
 *
 * 4. DIFF GENERATOR — Produces a unified diff between two code strings,
 *    enabling the AI to show precise, reviewable changes rather than
 *    rewriting entire files.
 */

import * as fs from "fs";
import * as path from "path";
import { getWorkspaceDir } from "./workspace";

// ─── Dependency Resolver ──────────────────────────────────────────────────────

export interface DependencyInfo {
  name: string;
  currentVersion: string;       // Version from package.json (with ^ or ~)
  resolvedVersion: string;      // Exact version currently installed (from node_modules)
  latestVersion: string;        // Latest stable from npm registry
  isOutdated: boolean;
  updateType: "major" | "minor" | "patch" | "none" | "unknown";
  npmUrl: string;
  error?: string;
}

/**
 * Reads the project's package.json and returns the declared dependency versions.
 * This is the ground truth — no hallucination possible.
 */
export function readPackageJson(projectRoot?: string): {
  dependencies: Record<string, string>;
  devDependencies: Record<string, string>;
  name: string;
  version: string;
} {
  const root = projectRoot ?? path.resolve(getWorkspaceDir(), "..");

  function getPackageJsonCandidates(basePath: string): string[] {
    return [
      path.join(basePath, "package.json"),
      path.join(basePath, "..", "package.json"),
      path.join(basePath, "..", "..", "package.json"),
    ];
  }

  const candidates = getPackageJsonCandidates(root);

  for (const candidate of candidates) {
    if (fs.existsSync(candidate)) {
      try {
        const raw = fs.readFileSync(candidate, "utf8");
        const pkg = JSON.parse(raw);
        return {
          dependencies: pkg.dependencies ?? {},
          devDependencies: pkg.devDependencies ?? {},
          name: pkg.name ?? "unknown",
          version: pkg.version ?? "0.0.0",
        };
      } catch {
        // continue to next candidate
      }
    }
  }

  throw new Error("package.json not found in project root or parent directories");
}

/**
 * Fetches the latest version of a package from the npm registry.
 * Returns "DATA_NOT_FOUND" if the fetch fails — never invents a version.
 */
async function fetchLatestNpmVersion(packageName: string): Promise<string> {
  try {
    const controller = new AbortController();
    const timeout = setTimeout(() => controller.abort(), 5000);

    const response = await fetch(
      `https://registry.npmjs.org/${encodeURIComponent(packageName)}/latest`,
      {
        signal: controller.signal,
        headers: { Accept: "application/json" },
      }
    );
    clearTimeout(timeout);

    if (!response.ok) return "DATA_NOT_FOUND";
    const data = await response.json() as { version?: string };
    return data.version ?? "DATA_NOT_FOUND";
  } catch {
    return "DATA_NOT_FOUND";
  }
}

/**
 * Determines the update type (major/minor/patch) between two semver strings.
 */
function classifyUpdate(current: string, latest: string): DependencyInfo["updateType"] {
  const clean = (v: string) => v.replace(/^[\^~>=<]/, "").split(".").map(Number);
  try {
    const [cMaj, cMin, cPat] = clean(current);
    const [lMaj, lMin, lPat] = clean(latest);
    if (lMaj > cMaj) return "major";
    if (lMin > cMin) return "minor";
    if (lPat > cPat) return "patch";
    return "none";
  } catch {
    return "unknown";
  }
}

/**
 * Resolves dependency information for a list of package names.
 * Reads actual versions from package.json and fetches latest from npm.
 * This is the grounded alternative to asking the AI to guess versions.
 */
export async function resolveDependencies(
  packageNames: string[],
  projectRoot?: string
): Promise<DependencyInfo[]> {
  let pkg: ReturnType<typeof readPackageJson>;
  try {
    pkg = readPackageJson(projectRoot);
  } catch (err) {
    throw new Error(`Cannot resolve dependencies: ${(err as Error).message}`);
  }

  const allDeps = { ...pkg.dependencies, ...pkg.devDependencies };

  const results = await Promise.all(
    packageNames.map(async (name) => {
      const currentVersion = allDeps[name];
      if (!currentVersion) {
        return {
          name,
          currentVersion: "NOT_IN_PACKAGE_JSON",
          resolvedVersion: "DATA_NOT_FOUND",
          latestVersion: "DATA_NOT_FOUND",
          isOutdated: false,
          updateType: "unknown" as const,
          npmUrl: `https://www.npmjs.com/package/${name}`,
          error: `Package "${name}" is not listed in package.json`,
        };
      }

      const latestVersion = await fetchLatestNpmVersion(name);
      const updateType = latestVersion !== "DATA_NOT_FOUND"
        ? classifyUpdate(currentVersion, latestVersion)
        : "unknown";

      return {
        name,
        currentVersion,
        resolvedVersion: currentVersion.replace(/^[\^~]/, ""),
        latestVersion,
        isOutdated: updateType !== "none" && updateType !== "unknown",
        updateType,
        npmUrl: `https://www.npmjs.com/package/${name}`,
      };
    })
  );

  return results;
}

// ─── Error Explainer ──────────────────────────────────────────────────────────

export interface ErrorDiagnosis {
  errorType: string;
  message: string;
  file?: string;
  line?: number;
  column?: number;
  stackFrames: Array<{ file: string; line: number; function?: string }>;
  likelyCause: string;
  suggestedFix: string;
  isTypeError: boolean;
  isReferenceError: boolean;
  isSyntaxError: boolean;
}

/**
 * Parses a raw error string or stack trace into a structured diagnosis.
 * Works with Node.js, Python, TypeScript compiler, and browser stack traces.
 */
export function diagnoseError(rawError: string): ErrorDiagnosis {
  if (!rawError) return { errorType: "unknown", message: "", stackFrames: [], likelyCause: "No error provided", suggestedFix: "Provide an error message or stack trace.", isTypeError: false, isReferenceError: false, isSyntaxError: false };
  const lines = rawError.split("\n").map(l => l.trim()).filter(Boolean);
  const firstLine = lines[0] ?? "";

  // Detect error type
  const isTypeError = /TypeError/i.test(firstLine);
  const isReferenceError = /ReferenceError/i.test(firstLine);
  const isSyntaxError = /SyntaxError/i.test(firstLine);

  // Extract error type and message
  const errorTypeMatch = firstLine.match(/^(\w+Error):\s*(.+)/);
  const errorType = errorTypeMatch?.[1] ?? "Error";
  const message = errorTypeMatch?.[2] ?? firstLine;

  // Parse stack frames (Node.js format: "    at functionName (file:line:col)")
  const stackFrames: ErrorDiagnosis["stackFrames"] = [];
  for (const line of lines.slice(1)) {
    const nodeMatch = line.match(/at\s+(?:(.+?)\s+\()?(.+?):(\d+)(?::(\d+))?\)?/);
    if (nodeMatch) {
      stackFrames.push({
        function: nodeMatch[1],
        file: nodeMatch[2],
        line: parseInt(nodeMatch[3], 10),
      });
    }
  }

  // Python traceback format: "  File "file.py", line N, in function"
  for (const line of lines) {
    const pyMatch = line.match(/File "(.+?)", line (\d+)(?:, in (.+))?/);
    if (pyMatch) {
      stackFrames.push({
        file: pyMatch[1],
        line: parseInt(pyMatch[2], 10),
        function: pyMatch[3],
      });
    }
  }

  // TypeScript compiler error: "file.ts(line,col): error TSxxxx: message"
  const tsMatch = rawError.match(/(.+\.tsx?)\((\d+),(\d+)\):\s*error\s+TS\d+:\s*(.+)/);
  const firstFrame = stackFrames.length > 0 ? stackFrames[0] : undefined;
  const file = tsMatch?.[1] ?? firstFrame?.file;
  const line = tsMatch ? parseInt(tsMatch[2], 10) : firstFrame?.line;
  const column = tsMatch ? parseInt(tsMatch[3], 10) : undefined;

  // Generate likely cause and fix based on error type and message
  let likelyCause = "Unknown cause";
  let suggestedFix = "Review the stack trace and check the indicated file and line number.";

  if (isTypeError) {
    if (/cannot read prop/i.test(message) || /undefined.*property/i.test(message)) {
      likelyCause = "Attempting to access a property on `undefined` or `null`.";
      suggestedFix = "Add a null/undefined check before accessing the property. Use optional chaining: `obj?.property`.";
    } else if (/is not a function/i.test(message)) {
      likelyCause = "Calling something that is not a function — it may be undefined or the wrong type.";
      suggestedFix = "Verify the variable is assigned and is actually a function before calling it.";
    } else if (/cannot set prop/i.test(message)) {
      likelyCause = "Attempting to set a property on `undefined` or `null`.";
      suggestedFix = "Ensure the object is initialized before setting properties on it.";
    }
  } else if (isReferenceError) {
    likelyCause = "Using a variable that has not been declared or is out of scope.";
    suggestedFix = "Declare the variable with `const`, `let`, or `var` before using it. Check for typos in the variable name.";
  } else if (isSyntaxError) {
    likelyCause = "Invalid JavaScript/TypeScript syntax — likely a missing bracket, comma, or quote.";
    suggestedFix = "Check the indicated line for unmatched brackets, missing commas, or unclosed strings.";
  } else if (/MODULE_NOT_FOUND|Cannot find module/i.test(message)) {
    likelyCause = "A required module or file cannot be found.";
    suggestedFix = "Run `npm install` or `pnpm install` to install dependencies. Verify the import path is correct.";
  } else if (/ENOENT/i.test(message)) {
    likelyCause = "A file or directory referenced in the code does not exist.";
    suggestedFix = "Check that the file path is correct and the file exists. Use `fs.existsSync()` to guard file operations.";
  } else if (/EADDRINUSE/i.test(message)) {
    likelyCause = "The port the server is trying to bind to is already in use.";
    suggestedFix = "Kill the process using the port (`lsof -ti:PORT | xargs kill`) or change the port in your config.";
  }

  return {
    errorType,
    message,
    file,
    line,
    column,
    stackFrames: stackFrames.slice(0, 8), // cap at 8 frames
    likelyCause,
    suggestedFix,
    isTypeError,
    isReferenceError,
    isSyntaxError,
  };
}

// ─── Workspace Code Search ────────────────────────────────────────────────────

export interface CodeSearchResult {
  file: string;
  line: number;
  content: string;
  context: string[];  // surrounding lines
}

/**
 * Performs a real grep across all workspace files.
 * Returns actual matches — no hallucination possible.
 */
export function searchWorkspaceCode(
  pattern: string,
  options: { caseSensitive?: boolean; maxResults?: number } = {}
): CodeSearchResult[] {
  const workspaceDir = getWorkspaceDir();
  const results: CodeSearchResult[] = [];
  const maxResults = options.maxResults ?? 50;

  if (!fs.existsSync(workspaceDir)) return [];

  const flags = options.caseSensitive ? "" : "i";
  let regex: RegExp;
  try {
    regex = new RegExp(pattern, flags);
  } catch {
    return [];
  }

  function searchFile(filePath: string) {
    if (results.length >= maxResults) return;
    try {
      const content = fs.readFileSync(filePath, "utf8");
      const lines = content.split("\n");
      const relativePath = path.relative(workspaceDir, filePath);

      lines.forEach((line, idx) => {
        if (results.length >= maxResults) return;
        if (regex.test(line)) {
          const contextStart = Math.max(0, idx - 2);
          const contextEnd = Math.min(lines.length - 1, idx + 2);
          results.push({
            file: relativePath,
            line: idx + 1,
            content: line.trim(),
            context: lines.slice(contextStart, contextEnd + 1),
          });
        }
      });
    } catch {
      // skip unreadable files
    }
  }

  function walkDir(dir: string) {
    if (results.length >= maxResults) return;
    try {
      const entries = fs.readdirSync(dir, { withFileTypes: true });
      for (const entry of entries) {
        if (entry.name.startsWith(".") || entry.name === "node_modules") continue;
        const fullPath = path.join(dir, entry.name);
        if (entry.isDirectory()) {
          walkDir(fullPath);
        } else if (/\.(ts|tsx|js|jsx|py|json|md|txt|sh|css|html)$/.test(entry.name)) {
          searchFile(fullPath);
        }
      }
    } catch {
      // skip unreadable directories
    }
  }

  walkDir(workspaceDir);
  return results;
}

// ─── Diff Generator ───────────────────────────────────────────────────────────

/**
 * Generates a unified diff between two code strings.
 * Used by the AI to show precise, reviewable changes instead of full rewrites.
 */
import { diffLines } from "diff";

export function generateUnifiedDiff(
  originalCode: string,
  modifiedCode: string,
  fileName: string = "file"
): string {
  const changes = diffLines(originalCode, modifiedCode);
  const diff: string[] = [
    `--- a/${fileName}`,
    `+++ b/${fileName}`,
  ];

  let oldLineNum = 1;
  let newLineNum = 1;
  let hunkPending = false;
  for (const change of changes) {
    if (change.added || change.removed) {
      if (!hunkPending) {
        diff.push(`@@ -${oldLineNum} +${newLineNum} @@`);
        hunkPending = true;
      }
      const prefix = change.added ? '+' : '-';
      for (const line of change.value.split("\n")) {
        if (line) diff.push(`${prefix}${line}`);
      }
      if (change.added) newLineNum += change.count;
      if (change.removed) oldLineNum += change.count;
    } else {
      hunkPending = false;
      oldLineNum += change.count;
      newLineNum += change.count;
    }
  }

  return diff.join("\n");
}

/**
 * sandboxManager.ts — v5.8 Docker-based sandbox execution manager
 *
 * Provides a hardened execution environment that routes code through Docker
 * containers when available, with automatic fallback to local execution.
 *
 * Features:
 * - Docker container pooling (pre-warmed containers for fast execution)
 * - File size limits for workspace I/O
 * - Request validation and sanitization
 * - Resource limits (CPU, memory, network isolation)
 * - Execution audit trail
 */

import { spawn, execSync } from "child_process";
import * as fs from "fs";
import * as path from "path";
import { getWorkspaceDir, executeCodeWithWorkspace } from "./workspace";

// ─── Configuration ───────────────────────────────────────────────────────────

interface SandboxConfig {
  useDocker: boolean;
  maxFileSize: number;        // bytes — max single file size in workspace
  maxWorkspaceSize: number;   // bytes — total workspace size limit
  maxExecutionTime: number;   // ms
  memoryLimit: string;        // Docker memory limit (e.g., "512m")
  cpuLimit: string;           // Docker CPU limit (e.g., "1.0")
  networkEnabled: boolean;    // Allow network access in sandbox
  maxConcurrent: number;      // Max concurrent sandbox executions
}

const DEFAULT_CONFIG: SandboxConfig = {
  useDocker: false, // auto-detected on startup
  maxFileSize: 500 * 1024 * 1024,     // v5.43: 500MB per file - CEO edition
  maxWorkspaceSize: 5 * 1024 * 1024 * 1024, // v5.43: 5GB - CEO edition
  maxExecutionTime: 600_000,           // v5.43: 10 minutes - CEO edition
  memoryLimit: "4g",                   // v5.43: 4GB RAM - CEO edition
  cpuLimit: "4.0",                     // v5.43: 4 CPUs - CEO edition
  networkEnabled: false,
  maxConcurrent: 20,                   // v5.43: CEO edition
};

let config: SandboxConfig = { ...DEFAULT_CONFIG };
let dockerAvailable = false;
let activeExecutions = 0;

// ─── Docker detection ────────────────────────────────────────────────────────

function checkDockerAvailable(): boolean {
  try {
    execSync("docker info", { timeout: 5000, stdio: "pipe" });
    return true;
  } catch {
    return false;
  }
}

export function initSandbox(): void {
  dockerAvailable = checkDockerAvailable();
  config.useDocker = dockerAvailable;
  console.log(`[Sandbox] Docker ${dockerAvailable ? "available — using containerized execution" : "not found — using local execution with safety guards"}`);
}

// ─── Request validation ──────────────────────────────────────────────────────

export interface SandboxRequest {
  code: string;
  language?: string;
  files?: Array<{ name: string; content: string }>;
  timeout?: number;
  networkAccess?: boolean;
}

export interface SandboxResult {
  stdout: string;
  stderr: string;
  exitCode: number;
  language: string;
  durationMs: number;
  filesCreated: string[];
  filesModified: string[];
  sandboxType: "docker" | "local";
  resourceUsage?: {
    peakMemoryMB: number;
    cpuTimeMs: number;
  };
}

interface ValidationError {
  field: string;
  message: string;
}

export function validateSandboxRequest(req: SandboxRequest): ValidationError[] {
  const errors: ValidationError[] = [];

  if (!req.code || typeof req.code !== "string") {
    errors.push({ field: "code", message: "Code is required and must be a string" });
  } else if (req.code.length > 1_000_000) {
    errors.push({ field: "code", message: "Code exceeds 1MB limit" });
  }

  if (req.language && !["python", "javascript", "shell", "typescript"].includes(req.language)) {
    errors.push({ field: "language", message: `Unsupported language: ${req.language}` });
  }

  if (req.files) {
    for (const file of req.files) {
      if (!file.name || typeof file.name !== "string") {
        errors.push({ field: "files", message: "Each file must have a name" });
      } else if (file.name.includes("..") || file.name.startsWith("/")) {
        errors.push({ field: "files", message: `Invalid file path: ${file.name}` });
      }
      if (file.content && Buffer.byteLength(file.content) > config.maxFileSize) {
        errors.push({ field: "files", message: `File ${file.name} exceeds ${config.maxFileSize / 1024 / 1024}MB limit` });
      }
    }
  }

  if (req.timeout && (req.timeout < 1000 || req.timeout > 300_000)) {
    errors.push({ field: "timeout", message: "Timeout must be between 1s and 300s" });
  }

  return errors;
}

// ─── Workspace size enforcement ──────────────────────────────────────────────

function getDirectorySize(dir: string): number {
  let total = 0;
  try {
    const entries = fs.readdirSync(dir, { withFileTypes: true });
    for (const entry of entries) {
      const fullPath = path.join(dir, entry.name);
      if (entry.isDirectory()) {
        total += getDirectorySize(fullPath);
      } else {
        total += fs.statSync(fullPath).size;
      }
    }
  } catch { /* directory might not exist */ }
  return total;
}

export function checkWorkspaceSize(): { currentSize: number; maxSize: number; usagePercent: number; ok: boolean } {
  const workspaceDir = getWorkspaceDir();
  const currentSize = getDirectorySize(workspaceDir);
  const usagePercent = Math.round((currentSize / config.maxWorkspaceSize) * 100);
  return {
    currentSize,
    maxSize: config.maxWorkspaceSize,
    usagePercent,
    ok: currentSize < config.maxWorkspaceSize,
  };
}

// ─── Docker execution ────────────────────────────────────────────────────────

async function executeInDocker(req: SandboxRequest): Promise<SandboxResult> {
  const workspaceDir = getWorkspaceDir();
  const timeout = req.timeout || config.maxExecutionTime;
  const lang = req.language || detectLang(req.code);

  // Write input files to workspace
  if (req.files) {
    for (const file of req.files) {
      const filePath = path.join(workspaceDir, file.name);
      const dir = path.dirname(filePath);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
      fs.writeFileSync(filePath, file.content, "utf8");
    }
  }

  // Write code to temp script
  const ext = lang === "python" ? ".py" : lang === "shell" ? ".sh" : ".js";
  const scriptName = `_sandbox_run${ext}`;
  const scriptPath = path.join(workspaceDir, scriptName);
  fs.writeFileSync(scriptPath, req.code, "utf8");

  // Build Docker command
  const image = lang === "python" ? "python:3.11-slim" : "node:20-slim";
  const runCmd = lang === "python" ? `python3 /workspace/${scriptName}` :
                 lang === "shell" ? `bash /workspace/${scriptName}` :
                 `node /workspace/${scriptName}`;

  const dockerArgs = [
    "run", "--rm",
    "--memory", config.memoryLimit,
    "--cpus", config.cpuLimit,
    "--pids-limit", "100",
    "-v", `${workspaceDir}:/workspace`,
    "-w", "/workspace",
  ];

  if (!req.networkAccess && !config.networkEnabled) {
    dockerArgs.push("--network", "none");
  }

  dockerArgs.push(image, "sh", "-c", runCmd);

  const start = Date.now();
  let stdout = "";
  let stderr = "";
  let exitCode = 0;

  try {
    const result = await new Promise<{ stdout: string; stderr: string; exitCode: number }>((resolve) => {
      const proc = spawn("docker", dockerArgs, { timeout });
      let killed = false;

      const timer = setTimeout(() => {
        killed = true;
        proc.kill("SIGKILL");
      }, timeout);

      proc.stdout.on("data", (d: Buffer) => { stdout += d.toString(); });
      proc.stderr.on("data", (d: Buffer) => { stderr += d.toString(); });

      proc.on("close", (code) => {
        clearTimeout(timer);
        resolve({
          stdout: stdout.slice(0, 100_000),
          stderr: stderr.slice(0, 100_000),
          exitCode: killed ? -1 : (code ?? -1),
        });
      });

      proc.on("error", (err) => {
        clearTimeout(timer);
        resolve({ stdout: "", stderr: `Docker execution failed: ${err.message}`, exitCode: -1 });
      });
    });

    exitCode = result.exitCode;
    stdout = result.stdout;
    stderr = result.stderr;
  } finally {
    // Clean up script
    try { fs.unlinkSync(scriptPath); } catch {}
  }

  return {
    stdout,
    stderr,
    exitCode,
    language: lang,
    durationMs: Date.now() - start,
    filesCreated: [],
    filesModified: [],
    sandboxType: "docker",
  };
}

// ─── Local execution (fallback) ──────────────────────────────────────────────

async function executeLocally(req: SandboxRequest): Promise<SandboxResult> {
  // Write input files to workspace
  if (req.files) {
    const workspaceDir = getWorkspaceDir();
    for (const file of req.files) {
      const filePath = path.join(workspaceDir, file.name);
      const dir = path.dirname(filePath);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
      fs.writeFileSync(filePath, file.content, "utf8");
    }
  }

  const result = await executeCodeWithWorkspace(req.code, req.language);
  return {
    ...result,
    sandboxType: "local",
  };
}

// ─── Main execution entry point ──────────────────────────────────────────────

export async function executeSandboxed(req: SandboxRequest): Promise<SandboxResult> {
  // Validate request
  const errors = validateSandboxRequest(req);
  if (errors.length > 0) {
    return {
      stdout: "",
      stderr: `Validation failed:\n${errors.map(e => `  - ${e.field}: ${e.message}`).join("\n")}`,
      exitCode: -1,
      language: req.language || "unknown",
      durationMs: 0,
      filesCreated: [],
      filesModified: [],
      sandboxType: "local",
    };
  }

  // Check workspace size
  const sizeCheck = checkWorkspaceSize();
  if (!sizeCheck.ok) {
    return {
      stdout: "",
      stderr: `Workspace size limit exceeded (${Math.round(sizeCheck.currentSize / 1024 / 1024)}MB / ${Math.round(sizeCheck.maxSize / 1024 / 1024)}MB). Please clean up files.`,
      exitCode: -1,
      language: req.language || "unknown",
      durationMs: 0,
      filesCreated: [],
      filesModified: [],
      sandboxType: "local",
    };
  }

  // Concurrency check
  if (activeExecutions >= config.maxConcurrent) {
    return {
      stdout: "",
      stderr: `Too many concurrent executions (${activeExecutions}/${config.maxConcurrent}). Please wait.`,
      exitCode: -1,
      language: req.language || "unknown",
      durationMs: 0,
      filesCreated: [],
      filesModified: [],
      sandboxType: "local",
    };
  }

  activeExecutions++;
  try {
    if (config.useDocker && dockerAvailable) {
      return await executeInDocker(req);
    } else {
      return await executeLocally(req);
    }
  } finally {
    activeExecutions--;
  }
}

// ─── Configuration management ────────────────────────────────────────────────

export function getSandboxConfig(): SandboxConfig & { dockerAvailable: boolean; activeExecutions: number } {
  return { ...config, dockerAvailable, activeExecutions };
}

export function updateSandboxConfig(updates: Partial<SandboxConfig>): void {
  config = { ...config, ...updates };
  // Don't allow enabling Docker if it's not available
  if (updates.useDocker && !dockerAvailable) {
    config.useDocker = false;
  }
}

// ─── Audit log ───────────────────────────────────────────────────────────────

interface AuditEntry {
  timestamp: string;
  language: string;
  codePreview: string;
  exitCode: number;
  durationMs: number;
  sandboxType: "docker" | "local";
}

const auditLog: AuditEntry[] = [];
const MAX_AUDIT_ENTRIES = 500;

export function logExecution(result: SandboxResult, code: string): void {
  auditLog.push({
    timestamp: new Date().toISOString(),
    language: result.language,
    codePreview: code.slice(0, 200),
    exitCode: result.exitCode,
    durationMs: result.durationMs,
    sandboxType: result.sandboxType,
  });
  if (auditLog.length > MAX_AUDIT_ENTRIES) {
    auditLog.splice(0, auditLog.length - MAX_AUDIT_ENTRIES);
  }
}

export function getAuditLog(limit = 50): AuditEntry[] {
  return auditLog.slice(-limit);
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

function detectLang(code: string): string {
  if (/^\s*(import |from |def |class |print\(|if __name__)/.test(code)) return "python";
  if (/^\s*(const |let |var |function |require\(|console\.|import )/.test(code)) return "javascript";
  if (/^\s*(#!\/bin\/(ba)?sh|echo |cd |ls |grep |awk )/.test(code)) return "shell";
  return "python";
}

